<script setup lang="ts">import{onMounted,ref}from'vue';import PageState from'../components/feedback/PageState.vue';import{listAuditLogs}from'../services/management/records';import type{AuditLog}from'../types/records';const items=ref<AuditLog[]>([]),loading=ref(true),error=ref(''),expanded=ref<string[]>([]),copied=ref('');async function load(){loading.value=true;try{items.value=(await listAuditLogs({pageSize:100})).data.items}catch(e){error.value=e instanceof Error?e.message:'审计日志加载失败'}finally{loading.value=false}}onMounted(load);function toggle(id:string){expanded.value=expanded.value.includes(id)?expanded.value.filter(v=>v!==id):[...expanded.value,id]}async function copy(id:string){await navigator.clipboard.writeText(id);copied.value=id}</script>
<template><div class="page"><header><p>READ-ONLY AUDIT</p><h1>操作审计</h1><span>只读记录管理员、目标对象、变更原因和请求编号</span></header><PageState v-if="loading&&items.length===0" status="loading"/><PageState v-else-if="error" status="error" :description="error" @retry="load"/><PageState v-else-if="items.length===0" status="empty" title="暂无审计记录"/><section v-else class="audit"><article v-for="log in items" :key="log.id"><div class="row"><span><strong>{{log.actor_username}}</strong><small>{{log.actor_role}}</small></span><span><strong>{{log.action}}</strong><small>{{log.target_type}} · {{log.target_id}}</small></span><span><strong>{{log.reason||'常规操作'}}</strong><small>{{log.created_at}}</small></span><code>{{log.request_id}}</code><button @click="copy(log.request_id)">{{copied===log.request_id?'已复制':'复制 request_id'}}</button><button @click="toggle(log.id)">{{expanded.includes(log.id)?'收起':'查看差异'}}</button></div><div v-if="expanded.includes(log.id)" class="diff"><section><h3>Before</h3><pre>{{JSON.stringify(log.before,null,2)}}</pre></section><section><h3>After</h3><pre>{{JSON.stringify(log.after,null,2)}}</pre></section></div></article></section></div></template>
<style scoped>@import '../styles/records-page.css';.audit{display:grid;gap:8px}.audit article{padding:13px;border:1px solid var(--tw-color-border);border-radius:var(--tw-radius-md);background:#fff}.row{display:grid;grid-template-columns:1fr 1.4fr 1.2fr 1fr auto auto;align-items:center;gap:10px}.row span{display:grid;gap:3px}.row small{color:var(--tw-color-muted);font-size:9px}.row code{overflow:hidden;text-overflow:ellipsis}.diff{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:12px}.diff section{min-width:0}.diff h3{font-size:11px}.diff pre{max-height:260px;overflow:auto;padding:11px;border-radius:8px;background:#172f29;color:#e8f4ef;font-size:10px;white-space:pre-wrap;overflow-wrap:anywhere}@media(max-width:900px){.row{grid-template-columns:1fr 1fr}.diff{grid-template-columns:1fr}}</style>
